SELECT * 
FROM publication_metrics
WHERE created_by = 0;

SELECT users.name, publications.title
FROM users
INNER JOIN publications ON users.user_id = publications.created_by;

SELECT p.title, p.authors
FROM publications AS p
WHERE p.publication_year = (SELECT MAX(publication_year) FROM publications);

SELECT r.topic_name, p.title, p.publication_year
FROM research_topics r
LEFT JOIN publications p ON r.topic_id = p.topic_id;

SELECT DISTINCT users.name, users.user_id
FROM users
JOIN research_topics ON users.user_id = research_topics.created_by;

SELECT topic_id, topic_name, num_publications
FROM research_topics
ORDER BY num_publications DESC;

SELECT title
FROM publications
WHERE topic_id = 0 AND publication_year = (SELECT most_recent_publication_year FROM research_topics WHERE topic_id = 0);
